UPDATE projects 
SET status = #{status}
,completed_on = SYSDATE
WHERE project_code = #{projectCode}

UPDATE projects 
SET project_name = #{projectName},
    description = #{description},
    status = #{status}
WHERE project_code = #{projectCode}

UPDATE project_role_user 
SET project_code = project_code * -1
WHERE mapp_code = #{mappCode}
  AND project_code = #{projectCode}

UPDATE project_role_user 
SET project_code = ABS(project_code),  
    role_code = #{roleCode}
WHERE user_code = #{userCode}
  AND project_code = #{projectCode} * -1

UPDATE gr_pro_role 
SET project_code = project_code * -1
WHERE gr_pro_code = #{grProCode}
  AND project_code = #{projectCode}

UPDATE gr_pro_role 
SET project_code = ABS(project_code),  
    role_code = #{roleCode}
WHERE gr_code = #{grCode}
  AND project_code = #{projectCode} * -1

